 1→import { FC, KeyboardEvent } from 'react';
 2→import Article from './Article';
 3→import { ArticleProps } from '../types/ArticleProps';
 4→interface ArticleListProps {
 5→  articles: ArticleProps[];
 6→  onArticleSelect?: (article: ArticleProps) => void;
 7→}
 8→
 9→const ArticleList: FC<ArticleListProps> = ({ articles, onArticleSelect }) => {
10→  const handleKeyPress = (e: KeyboardEvent<HTMLLIElement>, article: ArticleProps) => {
11→    if (e.key === 'Enter' || e.key === ' ') {
12→      e.preventDefault();
13→      onArticleSelect?.(article);
14→    }
15→  };
16→
17→  const handleClick = (article: ArticleProps) => {
18→    onArticleSelect?.(article);
19→  };
20→
21→  return (
22→    <nav aria-label="Articles navigation">
23→      <ul 
24→        role="list"
25→        className="articles-list"
26→      >
27→        {articles.map((article, index) => (
28→          <li 
29→            key={index}
30→            role="listitem"
31→            tabIndex={0}
32→            onClick={() => handleClick(article)}
33→            onKeyPress={(e) => handleKeyPress(e, article)}
34→            aria-label={`Article: ${article.title}`}
35→          >
36→            <Article {...article} />
37→          </li>
38→        ))}
39→      </ul>
40→    </nav>
41→  );
42→};
43→
44→export default ArticleList;

